    "startTimeSec": 747.3999999999999,
    "startFrame": 22422,
    "durationSec": 3.392,
    "durationFrames": 102,
    "speaker": "ずんだもん",
    "text": "チップ内部の熱ノイズで乱数を作る仕組みなのだ。",
