    "startTimeSec": 911.8706666666665,
    "startFrame": 27356,
    "durationSec": 6.634666666666667,
    "durationFrames": 199,
    "speaker": "めたん",
    "text": "「偏りがない」と「予測できない」が別の性質だなんて、最初は想像もしなかったですわ。",
    "speakerColor": "#d6336c",
    "sceneId": 23,
    "sceneTitle": "乱数の階層まとめ",
